INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_ARMY_NA_L0062$$, 2027, $$Army$$, $$PROC_ARMY$$, $$ARMY$$, NULL, $$62$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

Justification:
Fiscal Year (FY) 2027 Base procurement dollars in the amount of $13.228 million will support the procurement of 367 modernized Enhanced Portable Inductive Artillery Fuze Setter (EPIAFS) systems. These
systems will include an improved Platform Integration Kit (iPIK-M) and feature the ability to complete the Direct Set Interface required to set Precision Guidance Munitions (PGMs) and Fuzes with current and
future 155mm weapon systems. Funding will also support nonrecurring engineering efforts to mitigate obsolescence, upgrade software and improve platform integration components. These critical efforts will
reduce hardware obsolescence and system failures as well as enable flexibility and long-term viability in support of the Army's Field Artillery modernization objectives.

In accordance with section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110 - 181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
defense missions, domestic emergency responses, and providing military support to civil authorities.




